const entrada = items[0].json;

const termosSql_diretos = (entrada.Itens_diretos || [])
  .map(t => `'${t}'`)
  .join(', ');

const termosSql_nao_listados = (entrada.itens_nao_listados || [])
  .map(t => `'${t}'`)
  .join(', ');

const output = [];

if (termosSql_diretos) {
  output.push({ json: { termosSql_diretos } });
}
if (termosSql_nao_listados) {
  output.push({ json: { termosSql_nao_listados } });
}

return output;

// Coleta todos os resultados em um único array
const produtos = $input.all().map(item => item.json);

return [
  {
    json: {
      produtos // array com todos os produtos, do jeito que veio
    }
  }
];

const termosString = $json.termosSql_nao_listados; // ou items[0].json.termosSql_nao_encontrados

// Remove aspas simples iniciais/finais e divide nos termos
const termosArray = termosString
  .split(", '")            // divide pelos separadores
  .map(t => t.replace(/^'|'$/g, '').trim()); // remove aspas simples sobrando

return termosArray.map(termo => ({ json: { termo } }));

return items.map(item => {
  const termoOriginal = item.json.termo || item.json.descricao_produto || '';
  const termo = termoOriginal
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();

  const stopwords = [
    'de','da','do','a','o','e','para','com','em','as','os','na','no','por',
    'a','das','dos','um','uma','ao','nao'
  ];

  const palavras_chave = termo
    .replace(/[^\w\s/"]/g, '')
    .split(/[\s,;:-]+/)
    .filter(w => w.length > 1 && !stopwords.includes(w) && (isNaN(Number(w)) || w.length >= 4))
    .filter((w,i,arr) => arr.indexOf(w) === i);

  // === EXTRACAO DE CAMPOS ===
  const tipos = [
    'peneira','balanca','forma','molde','prensa','cilindro','copo','bandeja',
    'funil','ampola','proveta','soquete','conjunto','jogo','cone','talhadeira',
    'pipeta','marreta','papel filtro','paquimetro','termometro','fixador',
    'recipiente','aparelho','medidor','vane','extrator','repartidor','picnometro','brucutu','hilf'
  ];
  const tipo_principal = tipos.find(tp => termo.includes(tp)) || palavras_chave[0] || '';

  const formatos = ['cilindrico','quadrada','redonda','chata','circular','oval','retangular'];
  const materiais = [
    'aco inox','inox','aluminio','latao','ferro','vidro','plastico',
    'polipropileno','bronze','cobre','madeira','papel','acrilico','duraluminio',
    'acero','aco duro','aco'
  ];
  const formato  = formatos.find(f => termo.includes(f))  || '';
  const material = materiais.find(m => termo.includes(m)) || '';

  const matchDimensao = termo.match(/([0-9]+[,.]?[0-9]*)\s*[x\xd7]\s*([0-9]+[,.]?[0-9]*)(\s*(cm|mm|"))?/);
  const dimensao = matchDimensao
    ? matchDimensao[1] + 'x' + matchDimensao[2] + (matchDimensao[4] || '')
    : '';

  const matchVolume = termo.match(/([0-9]+[.,]?[0-9]*)\s*(l|ml|litros?|ampolas?|g|gr|kg|kgf)\b/);
  const volume = matchVolume ? matchVolume[1] + ' ' + matchVolume[2] : '';

  const matchMalha =
        termo.match(/\bpeneir\w*\s*([0-9]+(?:\/[0-9]+)?)/) ||
        termo.match(/malha\s*([0-9]+(?:\/[0-9]+)?)/);
  const malha = matchMalha ? matchMalha[1] : '';

  let abertura = '';
  let unidade_abertura = '';
  const matchAberturaMm =
        termo.match(/\(\s*([0-9]+[.,]?[0-9]*)\s*(mm|\xb5m|um|\u03bcm)\s*\)/) ||
        termo.match(/abertura\s*([0-9]+[.,]?[0-9]*)\s*(mm|\xb5m|um|\u03bcm)/);
  if (matchAberturaMm) {
    abertura = matchAberturaMm[1];
    unidade_abertura = matchAberturaMm[2];
  } else {
    const matchAberturaPol =
          termo.match(/([0-9]+\/[0-9]+)\s*("|''|in|pol)/) ||
          termo.match(/abertura\s*([0-9]+\/[0-9]+)\s*("|''|in|pol)/);
    if (matchAberturaPol) {
      abertura = matchAberturaPol[1];
      unidade_abertura = 'pol';
    }
  }

  const matchVoltagem = termo.match(/([0-9]{2,3})\s*v\b/);
  const voltagem = matchVoltagem ? matchVoltagem[1] + 'V' : '';

  const matchCapacidade = termo.match(/([0-9]+)\s*(ton|toneladas?|t)\b/);
  const capacidade = matchCapacidade ? matchCapacidade[1] : '';

  // === MONTAR FILTROS WHERE ===
  const safe = (s) => s.replace(/'/g, "''");

  const filtros = [];

  if (tipo_principal) {
    filtros.push({
      campo: 'tipo',
      prioridade: 1,
      sql: "unaccent(descricao_produto) ILIKE '%" + safe(tipo_principal) + "%'"
    });
  }

  if (malha) {
    filtros.push({
      campo: 'malha',
      prioridade: 2,
      sql: "unaccent(descricao_produto) ~* 'malha[ ]*" + safe(malha) + "([^0-9/]|$)'"
    });
  }

  if (dimensao) {
    const dimNum = dimensao.replace(/[^0-9x]/g, '');
    filtros.push({
      campo: 'dimensao',
      prioridade: 3,
      sql: "regexp_replace(unaccent(descricao_produto), '[^0-9x]', '', 'g') ILIKE '%" + safe(dimNum) + "%'"
    });
  }

  if (voltagem) {
    filtros.push({
      campo: 'voltagem',
      prioridade: 4,
      sql: "(descricao_produto ILIKE '%" + safe(voltagem) + "%' OR descricao_produto ILIKE '%" + safe(voltagem.replace('V','')) + "/%V%')"
    });
  }

  if (capacidade) {
    filtros.push({
      campo: 'capacidade',
      prioridade: 4,
      sql: "unaccent(descricao_produto) ~* '" + safe(capacidade) + "\\s*(ton|t|kg)\\b'"
    });
  }

  if (volume) {
    // Separar numero e unidade pra usar \s* entre eles (ex: "15kg" e "15 kg")
    const volMatch = volume.match(/([0-9]+[.,]?[0-9]*)\s*(.*)/);
    const volNum = volMatch ? volMatch[1] : volume;
    const volUnit = volMatch ? volMatch[2] : '';
    const volSql = volUnit
      ? "unaccent(descricao_produto) ~* '" + safe(volNum) + "\\s*" + safe(volUnit) + "([^0-9]|$)'"
      : "unaccent(descricao_produto) ~* '" + safe(volNum) + "([^0-9]|$)'"
    filtros.push({
      campo: 'volume',
      prioridade: 5,
      sql: volSql
    });
  }

  if (material) {
    filtros.push({
      campo: 'material',
      prioridade: 6,
      sql: "unaccent(descricao_produto) ILIKE '%" + safe(material) + "%'"
    });
  }

  if (abertura) {
    filtros.push({
      campo: 'abertura',
      prioridade: 7,
      sql: "unaccent(descricao_produto) ~* '" + safe(abertura) + "\\s*" + safe(unidade_abertura || 'mm') + "'"
    });
  }

  if (formato) {
    filtros.push({
      campo: 'formato',
      prioridade: 8,
      sql: "unaccent(descricao_produto) ILIKE '%" + safe(formato) + "%'"
    });
  }

  // Palavras-chave extras — excluir tudo que ja ta coberto por filtros especificos
  const cobertos = new Set();
  if (tipo_principal) cobertos.add(tipo_principal);
  if (malha) { cobertos.add(malha); cobertos.add('malha'); }
  if (dimensao) {
    dimensao.replace(/[^0-9x]/g, '').split('x').forEach(d => { if (d) cobertos.add(d); });
    cobertos.add(dimensao.replace(/[^0-9x]/g, ''));
  }
  if (voltagem) { cobertos.add(voltagem.toLowerCase()); cobertos.add(voltagem.replace('V','').toLowerCase()); }
  if (volume) { volume.split(/s+/).forEach(v => { if (v) cobertos.add(v); }); }
  if (capacidade) { cobertos.add(capacidade); cobertos.add('ton'); cobertos.add('toneladas'); }
  if (material) cobertos.add(material);
  if (formato) cobertos.add(formato);
  if (abertura) { cobertos.add(abertura); cobertos.add(unidade_abertura); }

  const palavrasExtras = palavras_chave.filter(p => !cobertos.has(p));
  if (palavrasExtras.length > 0) {
    const kwSql = palavrasExtras.map(p =>
      "unaccent(descricao_produto) ILIKE '%" + safe(p) + "%'"
    ).join(' AND ');
    filtros.push({
      campo: 'keywords',
      prioridade: 9,
      sql: kwSql
    });
  }

  filtros.sort((a, b) => a.prioridade - b.prioridade);

  // === MONTAR SQL CASCATA ===
  const tipoFilter = filtros.find(f => f.campo === 'tipo');
  const specFilters = filtros.filter(f => f.campo !== 'tipo');

  const baseWhere = tipoFilter ? tipoFilter.sql : 'TRUE';
  const allSpecs = specFilters.map(f => f.sql);

  const strictWhere = [baseWhere, ...allSpecs].join(' AND ');

  const halfSpecs = allSpecs.slice(0, Math.max(1, Math.ceil(allSpecs.length / 2)));
  const mediumWhere = [baseWhere, ...halfSpecs].join(' AND ');

  const simTermoSafe = safe(termo);
  const priceFilter = "preco::numeric > 0";

  let query_sql;

  if (allSpecs.length === 0) {
    query_sql = "SELECT nome_produto, descricao_produto, preco, "
      + "similarity(unaccent(lower(descricao_produto)), unaccent('" + simTermoSafe + "')) as sim, "
      + "'broad' as match_level "
      + "FROM produtos_tabela_preco_marcelo "
      + "WHERE " + baseWhere + " AND " + priceFilter + " "
      + "ORDER BY sim DESC LIMIT 15;";
  } else if (allSpecs.length === 1) {
    query_sql = "WITH strict AS ("
      + " SELECT nome_produto, descricao_produto, preco FROM produtos_tabela_preco_marcelo"
      + " WHERE " + strictWhere + " AND " + priceFilter + " LIMIT 10"
      + "), broad AS ("
      + " SELECT nome_produto, descricao_produto, preco FROM produtos_tabela_preco_marcelo"
      + " WHERE NOT EXISTS (SELECT 1 FROM strict)"
      + " AND " + baseWhere + " AND " + priceFilter
      + " ORDER BY similarity(unaccent(lower(descricao_produto)), unaccent('" + simTermoSafe + "')) DESC LIMIT 15"
      + ") "
      + "SELECT *, 'strict' as match_level FROM strict "
      + "UNION ALL SELECT *, 'broad' as match_level FROM broad;";
  } else {
    query_sql = "WITH strict AS ("
      + " SELECT nome_produto, descricao_produto, preco FROM produtos_tabela_preco_marcelo"
      + " WHERE " + strictWhere + " AND " + priceFilter + " LIMIT 10"
      + "), medium AS ("
      + " SELECT nome_produto, descricao_produto, preco FROM produtos_tabela_preco_marcelo"
      + " WHERE NOT EXISTS (SELECT 1 FROM strict)"
      + " AND " + mediumWhere + " AND " + priceFilter + " LIMIT 10"
      + "), broad AS ("
      + " SELECT nome_produto, descricao_produto, preco FROM produtos_tabela_preco_marcelo"
      + " WHERE NOT EXISTS (SELECT 1 FROM strict) AND NOT EXISTS (SELECT 1 FROM medium)"
      + " AND " + baseWhere + " AND " + priceFilter
      + " ORDER BY similarity(unaccent(lower(descricao_produto)), unaccent('" + simTermoSafe + "')) DESC LIMIT 15"
      + ") "
      + "SELECT *, 'strict' as match_level FROM strict "
      + "UNION ALL SELECT *, 'medium' as match_level FROM medium "
      + "UNION ALL SELECT *, 'broad' as match_level FROM broad;";
  }

  return {
    json: {
      termo: termoOriginal,
      tipo_principal,
      formato,
      material,
      dimensao,
      volume,
      malha,
      abertura,
      unidade_abertura,
      voltagem,
      capacidade,
      palavras_chave,
      filtros_usados: filtros.map(f => f.campo),
      query_sql
    }
  };
});

// Parser do output do LLM Classificador
const llmOutput = $input.first().json;
let response;

try {
  const text = llmOutput.text || llmOutput.response || JSON.stringify(llmOutput);
  // Extrair JSON da resposta (caso tenha texto extra)
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  response = JSON.parse(jsonMatch[0]);
} catch(e) {
  // Fallback: tratar como item unico nao listado
  const rawItem = $('When Executed by Another Workflow').first().json.Item || '';
  return [{ json: { Itens_diretos: [], itens_nao_listados: [rawItem.toUpperCase()] } }];
}

const itens = response.itens || [];
const Itens_diretos = [];
const itens_nao_listados = [];

for (const item of itens) {
  if (item.termo) {
    Itens_diretos.push(item.termo);
  } else {
    let searchTerm = (item.item_original || '').toUpperCase();

    if (item.especificacoes) {
      // Remover da especificacao palavras que ja existem no item_original
      const originalWords = new Set(searchTerm.toLowerCase().split(/\s+/));
      const specWords = item.especificacoes.toLowerCase().split(/\s+/);
      const novas = specWords.filter(w => !originalWords.has(w));
      if (novas.length > 0) {
        searchTerm = searchTerm + ' ' + novas.join(' ').toUpperCase();
      }
    }

    itens_nao_listados.push(searchTerm);
  }
}

return [{ json: { Itens_diretos, itens_nao_listados } }];

const produtos = items[0].json.data || [];

if (produtos.length === 0) {
  return [{ json: { topProdutos: [], outrosProdutos: [] } }];
}

// Priorizar por nivel de match
const strict = produtos.filter(p => p.match_level === 'strict');
const medium = produtos.filter(p => p.match_level === 'medium');
const broad  = produtos.filter(p => p.match_level === 'broad');

let topProdutos;

if (strict.length > 0) {
  topProdutos = strict.slice(0, 8);
} else if (medium.length > 0) {
  topProdutos = medium.slice(0, 8);
} else {
  topProdutos = broad.slice(0, 8);
}

if (topProdutos.length === 0 && produtos.length > 0) {
  topProdutos = [produtos[0]];
}

const outrosProdutos = produtos.filter(p => !topProdutos.includes(p));

return [{ json: { topProdutos, outrosProdutos } }];

